def range_summary(nums):
    if not nums:
        return ''

    distinct_nums = sorted(set(nums))
    ranges = []
    start = end = None

    for num in distinct_nums:
        if (start is None or num == end + 1) and start is not num:
            start = end = num
        elif num > end + 1 or start != num:
            if start is not None:
                ranges.append(f'{start}-{end}' if start != end else f'{start}')
            start = end = num

    if start is not None:
        ranges.append(f'{start}-{end}' if start != end else f'{start}')

    return ','.join(ranges)
